import Foundation

/// Paths for files generated by the `generate-swiftiomatic` tool.
///
/// Create with a package root URL. For the standalone executable,
/// use the ``filePath`` convenience that derives the root from `#filePath`.
package struct GeneratePaths {

    // MARK: - Convenience for standalone executable

    /// Paths derived from this source file's location (`Sources/GeneratorKit/`).
    package static let filePath = GeneratePaths(
        packageRoot: URL(fileURLWithPath: #filePath)
            .deletingLastPathComponent()  // GeneratorKit/
            .deletingLastPathComponent()  // Sources/
            .deletingLastPathComponent()  // package root
    )

    // MARK: - Instance properties

    /// The package root directory.
    package let packageRoot: URL

    /// The directory containing rule implementations to scan.
    package let rulesDirectory: URL

    /// The directory containing layout setting descriptors to scan.
    package let settingsDirectory: URL

    /// The directory containing `TokenStream+*.swift` token stream extension files.
    package let tokenStreamDirectory: URL

    /// The generated pipelines file (`LintPipeline` + `FormatPipeline` extensions).
    package let pipelineFile: URL

    /// The generated rule registry file (type arrays, default enablements, name cache).
    package let ruleRegistryFile: URL

    /// The generated rule documentation markdown file.
    package let ruleDocumentationFile: URL

    /// The generated JSON Schema for configuration files.
    package let configurationSchemaFile: URL

    /// The generated `TokenStream` subclass with forwarding stubs.
    package let tokenStreamStubsFile: URL

    // MARK: - Initializers

    /// Creates paths rooted at the given package directory.
    package init(packageRoot: URL) {
        let generated = packageRoot
            .appending(path: "Sources")
            .appending(path: "SwiftiomaticKit")
            .appending(path: "Generated")
        self.init(packageRoot: packageRoot, outputDirectory: generated)
    }

    /// Creates paths with input directories derived from `packageRoot`
    /// and output files directed to `outputDirectory`.
    ///
    /// Used by the build tool plugin to write generated files into the
    /// plugin work directory instead of the source tree.
    package init(packageRoot: URL, outputDirectory: URL) {
        self.packageRoot = packageRoot

        let sources = packageRoot.appending(path: "Sources")
        let kit = sources.appending(path: "SwiftiomaticKit")
        let syntax = kit.appending(path: "Syntax")

        rulesDirectory = syntax.appending(path: "Rules")
        settingsDirectory = kit.appending(path: "Layout")
            .appending(path: "Rules")
        tokenStreamDirectory = kit.appending(path: "Layout")
            .appending(path: "Tokens")

        pipelineFile = outputDirectory.appending(path: "Pipelines+Generated.swift")
        ruleRegistryFile = outputDirectory.appending(path: "ConfigurationRegistry+Generated.swift")
        ruleDocumentationFile = packageRoot.appending(path: "Documentation")
            .appending(path: "RuleDocumentation.md")
        configurationSchemaFile = packageRoot.appending(path: "schema.json")
        tokenStreamStubsFile = outputDirectory.appending(path: "TokenStream+Generated.swift")
    }
}
